class Solution:
    def buttonWithLongestTime(self, events):
        prev = 0
        rows = []
        for i, (idx, t) in enumerate(events):
            dur = t if i == 0 else t - prev
            rows.append((idx, dur))
            prev = t
        rows.sort(key=lambda r: (-r[1], r[0]))
        return rows[0][0]

