class Solution:
    def buttonWithLongestTime(self, events):
        best_idx, best_time = events[0]
        prev_time = events[0][1]
        for idx, t in events[1:]:
            dur = t - prev_time
            if dur > best_time or (dur == best_time and idx < best_idx):
                best_time = dur
                best_idx = idx
            prev_time = t
        return best_idx

