var buttonWithLongestTime = function(events) {
    let bestIdx = events[0][0];
    let bestTime = events[0][1];
    let prevTime = events[0][1];
    for (let i = 1; i < events.length; i++) {
        const [idx, t] = events[i];
        const dur = t - prevTime;
        if (dur > bestTime || (dur === bestTime && idx < bestIdx)) {
            bestTime = dur;
            bestIdx = idx;
        }
        prevTime = t;
    }
    return bestIdx;
};
